import React, { useState, useEffect } from "react";
import { Plus, Edit2, Trash2, Save, X, Eye, EyeOff } from "lucide-react";

const AdminDashboard = ({ onLogout }) => {
  const API_BASE = "http://localhost:5000/api";
  const serverBase = API_BASE.replace('/api', '');

  const getFullUrl = (p) => {
    if (!p) return '/images/placeholder.jpg';
    const clean = p.startsWith('/') ? p.slice(1) : p;
    return `${serverBase}/${clean}`;
  };
  const [adminPassword, setAdminPassword] = useState("");
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [showPassword, setShowPassword] = useState(false);

  // Tab navigation
  const [activeTab, setActiveTab] = useState("categories");

  // Edit states
  const [editingId, setEditingId] = useState(null);
  const [editData, setEditData] = useState({});

  // Add new states
  const [showAddForm, setShowAddForm] = useState(false);
  const [newItemType, setNewItemType] = useState("");
  const [newItem, setNewItem] = useState({});

  // Delete confirmation state
  const [confirmDelete, setConfirmDelete] = useState(null);

  // Fetch data after authentication
  const fetchData = async () => {
    try {
      setLoading(true);
      const response = await fetch(`${API_BASE}/getData`);
      const result = await response.json();
      setData(result);
      setError("");
    } catch (err) {
      setError("Failed to load data: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  // Handle login (verify password with server)
  const handleLogin = async (e) => {
    e.preventDefault?.();
    try {
      setLoading(true);
      const res = await fetch(`${API_BASE}/updateData`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ password: adminPassword, action: 'verify' }),
      });
      if (res.ok) {
        setIsAuthenticated(true);
        setError('');
        await fetchData();
      } else {
        const body = await res.json().catch(() => ({}));
        setError(body.error || 'Authentication failed');
      }
    } catch (err) {
      setError('Login error: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  // Handle delete actions for various types
  const handleDelete = async (type, id) => {
    try {
      if (type === 'product') {
        const categoryIndex = data.categories.findIndex(c =>
          c.subProducts.some(p => p.name === id)
        );
        if (categoryIndex === -1) return;
        const prodIndex = data.categories[categoryIndex].subProducts.findIndex(p => p.name === id);
        await updateDataOnServer('deleteProduct', { catIndex: categoryIndex, prodIndex });
      } else if (type === 'category') {
        const catIndex = data.categories.findIndex(c => c.category === id);
        if (catIndex === -1) return;
        await updateDataOnServer('deleteCategory', { index: catIndex });
      } else if (type === 'gallery') {
        const galleryIndex = data.gallery.findIndex(g => g.id === id);
        if (galleryIndex === -1) return;
        await updateDataOnServer('deleteGalleryImage', { index: galleryIndex });
      } else if (type === 'client') {
        const idx = Number(id);
        await updateDataOnServer('deleteClient', { index: idx });
      }
    } catch (err) {
      setError('Delete failed: ' + err.message);
    }
  };

  // Update data on server - use action-based API
  // If `files` is provided (array of File objects), send FormData so multer on server can save them.
  const updateDataOnServer = async (action, payload = {}, files = null) => {
    try {
      let response;
      if (files && files.length) {
        const fd = new FormData();
        fd.append('password', adminPassword);
        fd.append('action', action);
        // append payload fields (strings or JSON)
        Object.keys(payload || {}).forEach((k) => {
          const val = payload[k];
          if (typeof val === 'string' || typeof val === 'number' || typeof val === 'boolean') {
            fd.append(k, String(val));
          } else {
            fd.append(k, JSON.stringify(val));
          }
        });
        // append files under the `files` field (server uses multer.any())
        for (let i = 0; i < files.length; i++) fd.append('files', files[i]);

        response = await fetch(`${API_BASE}/updateData`, {
          method: 'POST',
          body: fd,
        });
      } else {
        response = await fetch(`${API_BASE}/updateData`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ password: adminPassword, action, ...payload }),
        });
      }

      const result = await response.json().catch(() => ({}));
      if (response.ok) {
        // Refresh data after successful update
        const dataRes = await fetch(`${API_BASE}/getData`);
        const freshData = await dataRes.json();
        setData(freshData);
        setSuccess('Data updated successfully!');
        setEditingId(null);
        setTimeout(() => setSuccess(''), 3000);
        return true;
      } else {
        setError(result.error || 'Failed to update data');
        return false;
      }
    } catch (err) {
      setError('Update failed: ' + err.message);
      return false;
    }
  };

  // Handle edit save
  const handleEditSave = async (type, id) => {
    if (type === "companyInfo") {
      const success = await updateDataOnServer("updateCompanyInfo", {
        companyInfo: JSON.stringify(editData),
      });
      if (success) setEditingId(null);
    } else if (type === "category") {
      const categoryIndex = data.categories.findIndex(c => c.category === id);
      const success = await updateDataOnServer("updateCategory", {
        catIndex: categoryIndex,
        category: JSON.stringify(editData),
      });
      if (success) setEditingId(null);
    } else if (type === "product") {
      const categoryIndex = data.categories.findIndex(c =>
        c.subProducts.some(p => p.name === id)
      );
      const productIndex = data.categories[categoryIndex].subProducts.findIndex(
        p => p.name === id
      );
      // remove file objects from updates before stringifying
      const { newFiles, removedImages, ...updatesObj } = editData || {};
      const files = newFiles || null;
      const success = await updateDataOnServer(
        "updateProduct",
        { catIndex: categoryIndex, prodIndex: productIndex, updates: updatesObj, deleteImages: removedImages || [] },
        files
      );
      if (success) setEditingId(null);
    } else if (type === "gallery") {
      const galleryIndex = data.gallery.findIndex(g => g.id === id);
      const { newFiles, ...updates } = editData || {};
      const files = newFiles || null;
      const success = await updateDataOnServer("updateGalleryImage", { index: galleryIndex, image: updates }, files);
      if (success) setEditingId(null);
    } else if (type === "client") {
      // id is the client index
      const idx = Number(id);
      const newName = (editData.name || '').trim();
      if (!newName) {
        setError('Client name cannot be empty');
        return;
      }

      const delOk = await updateDataOnServer('deleteClient', { index: idx });
      if (!delOk) return;

      const addOk = await updateDataOnServer('addClient', { client: newName });
      if (addOk) {
        setEditingId(null);
      }
    }
  };

  // Handle add new item
  const handleAddNew = async (e) => {
    e.preventDefault();

    try {
      if (newItemType === "category") {
        const newCategory = {
          category: newItem.categoryName,
          subProducts: [],
        };
        const files = newItem.categoryFiles || null;
        const success = await updateDataOnServer("addCategory", { category: newCategory }, files);
        if (success) {
          setShowAddForm(false);
          setNewItem({});
          setNewItemType("");
        }
      } else if (newItemType === "product") {
        const categoryIndex = data.categories.findIndex(
          c => c.category === newItem.categorySelect
        );
        if (categoryIndex === -1) {
          setError('Please select a valid category');
          return;
        }
        const product = {
          name: newItem.productName,
          price: newItem.productPrice,
          description: newItem.productDescription,
        };
        const files = newItem.productFiles || null;
        const success = await updateDataOnServer(
          'addProduct',
          { catIndex: categoryIndex, product: product },
          files
        );
        if (success) {
          setShowAddForm(false);
          setNewItem({});
          setNewItemType("");
        }
      } else if (newItemType === "gallery") {
        const files = newItem.galleryFiles || null;
        const success = await updateDataOnServer(
          'addGalleryImage',
          { caption: newItem.galleryTitle, image: newItem.galleryImage },
          files
        );
        if (success) {
          setShowAddForm(false);
          setNewItem({});
          setNewItemType("");
        }
      } else if (newItemType === "client") {
        const name = (newItem.clientName || '').trim();
        if (!name) {
          setError('Client name cannot be empty');
          return;
        }
        const files = newItem.clientFiles || null;
        const success = await updateDataOnServer('addClient', { client: name }, files);
        if (success) {
          setShowAddForm(false);
          setNewItem({});
          setNewItemType("");
        }
      }
    } catch (err) {
      setError('Add failed: ' + err.message);
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="flex items-center justify-center min-h-screen p-6 bg-slate-50">
        <div className="w-full max-w-md p-6 bg-white rounded-lg shadow-lg">
          <div className="flex items-center gap-3 mb-4">
            <div className="text-2xl">🔐</div>
            <h1 className="text-xl font-semibold">Admin Dashboard</h1>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700">Admin Password</label>
              <div className="relative mt-1">
                <input
                  type={showPassword ? "text" : "password"}
                  value={adminPassword}
                  onChange={(e) => setAdminPassword(e.target.value)}
                  placeholder="Enter admin password"
                  disabled={loading}
                  className="block w-full px-3 py-2 border rounded-md shadow-sm border-slate-300 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-2 top-2 text-slate-500 hover:text-slate-700"
                  aria-label="Toggle password visibility"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            {error && (
              <div className="p-2 text-sm text-red-600 border border-red-100 rounded bg-red-50">{error}</div>
            )}

            <div className="flex items-center gap-3">
              <button
                type="submit"
                disabled={loading}
                className="inline-flex items-center gap-2 px-4 py-2 text-white bg-indigo-600 rounded hover:bg-indigo-700 disabled:opacity-60"
              >
                {loading ? "Authenticating..." : "Login"}
              </button>
              <button
                type="button"
                onClick={() => setAdminPassword("")}
                className="text-sm text-slate-600 hover:text-slate-800"
              >
                Clear
              </button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  if (loading && !data) {
    return <div className="admin-loading">Loading dashboard...</div>;
  }

  return (
    <div className="min-h-screen p-6 bg-slate-50">
      <div className="mx-auto max-w-7xl">
        <header className="flex items-center justify-between mb-6">
          <div>
            <h1 className="text-2xl font-bold">📊 Admin Dashboard</h1>
            <p className="text-sm text-slate-500">Manage site data, gallery, clients and products</p>
          </div>
          <div className="flex items-center gap-3">
            <button
              onClick={onLogout}
              className="px-3 py-2 text-sm bg-white border rounded shadow-sm border-slate-200 hover:bg-slate-50"
            >
              Logout
            </button>
          </div>
        </header>

        {error && <div className="p-3 mb-4 text-sm text-red-700 border border-red-100 rounded bg-red-50">{error}</div>}
        {success && <div className="p-3 mb-4 text-sm text-green-700 border border-green-100 rounded bg-green-50">{success}</div>}

        <nav className="flex gap-2 p-3 mb-6 overflow-auto bg-white rounded shadow-sm">
          <button
            className={`px-3 py-2 rounded text-sm ${activeTab === 'company' ? 'bg-indigo-600 text-white' : 'text-slate-700 hover:bg-slate-100'}`}
            onClick={() => setActiveTab('company')}
          >
            Company Info
          </button>
          <button
            className={`px-3 py-2 rounded text-sm ${activeTab === 'categories' ? 'bg-indigo-600 text-white' : 'text-slate-700 hover:bg-slate-100'}`}
            onClick={() => setActiveTab('categories')}
          >
            Categories & Products
          </button>
          <button
            className={`px-3 py-2 rounded text-sm ${activeTab === 'gallery' ? 'bg-indigo-600 text-white' : 'text-slate-700 hover:bg-slate-100'}`}
            onClick={() => setActiveTab('gallery')}
          >
            Gallery
          </button>
          <button
            className={`px-3 py-2 rounded text-sm ${activeTab === 'clients' ? 'bg-indigo-600 text-white' : 'text-slate-700 hover:bg-slate-100'}`}
            onClick={() => setActiveTab('clients')}
          >
            Clients
          </button>
        </nav>

        <main className="p-6 bg-white rounded shadow">
        {/* Company Info Tab */}
        {activeTab === "company" && data?.companyInfo && (
          <div className="section">
            <h2>Company Information</h2>
            {editingId === "company" ? (
              <form className="edit-form">
                <div className="form-group">
                  <label>Name</label>
                  <input
                    type="text"
                    value={editData.name || ""}
                    onChange={(e) =>
                      setEditData({ ...editData, name: e.target.value })
                    }
                  />
                </div>
                <div className="form-group">
                  <label>Description</label>
                  <textarea
                    value={editData.description || ""}
                    onChange={(e) =>
                      setEditData({ ...editData, description: e.target.value })
                    }
                    rows="5"
                  />
                </div>
                <div className="flex gap-2 mt-3">
                  <button
                    type="button"
                    className="inline-flex items-center gap-2 px-3 py-2 text-white bg-green-600 rounded hover:bg-green-700"
                    onClick={() => handleEditSave("companyInfo", "company")}
                  >
                    <Save size={18} /> Save
                  </button>
                  <button
                    type="button"
                    className="inline-flex items-center gap-2 px-3 py-2 text-white bg-red-600 rounded hover:bg-red-700"
                    onClick={() => setEditingId(null)}
                  >
                    <X size={18} /> Cancel
                  </button>
                </div>
              </form>
            ) : (
              <div className="info-card">
                <p>
                  <strong>Name:</strong> {data.companyInfo.name}
                </p>
                <p>
                  <strong>Description:</strong> {data.companyInfo.description}
                </p>
                <button
                  className="inline-flex items-center gap-2 px-3 py-2 text-white bg-indigo-600 rounded hover:bg-indigo-700"
                  onClick={() => {
                    setEditingId("company");
                    setEditData(data.companyInfo);
                  }}
                >
                  <Edit2 size={18} /> Edit
                </button>
              </div>
            )}
          </div>
        )}

        {/* Categories & Products Tab */}
        {activeTab === "categories" && data?.categories && (
          <div className="section">
            <h2>Categories & Products</h2>
            <button
              className="inline-flex items-center gap-2 px-3 py-2 text-white bg-indigo-600 rounded hover:bg-indigo-700"
              onClick={() => {
                setShowAddForm(true);
                setNewItemType("category");
              }}
            >
              <Plus size={18} /> Add Category
            </button>
            {/* Global Add Product removed - use per-category Add Product buttons */}

            {showAddForm && (newItemType === "category" || newItemType === "product") && (
              <form className="add-form" onSubmit={handleAddNew}>
                {newItemType === "category" && (
                  <div className="form-group">
                    <label>Category Name</label>
                    <input
                      type="text"
                      placeholder="e.g., Sign Board"
                      value={newItem.categoryName || ""}
                      onChange={(e) =>
                        setNewItem({ ...newItem, categoryName: e.target.value })
                      }
                      required
                    />
                    <div style={{ marginTop: 8 }}>
                      <label>Category Images (optional)</label>
                      <input
                        type="file"
                        accept="image/*"
                        multiple
                        onChange={(e) =>
                          setNewItem({ ...newItem, categoryFiles: Array.from(e.target.files) })
                        }
                      />
                    </div>
                  </div>
                )}

                {newItemType === "product" && (
                  <>
                    <div className="form-group">
                      <label>Category</label>
                      <select
                        value={newItem.categorySelect || ""}
                        onChange={(e) =>
                          setNewItem({
                            ...newItem,
                            categorySelect: e.target.value,
                          })
                        }
                        required
                      >
                        <option value="">Select Category</option>
                        {data.categories.map((cat) => (
                          <option key={cat.category} value={cat.category}>
                            {cat.category}
                          </option>
                        ))}
                      </select>
                    </div>
                    <div className="form-group">
                      <label>Product Name</label>
                      <input
                        type="text"
                        placeholder="e.g., Acrylic Sign Board"
                        value={newItem.productName || ""}
                        onChange={(e) =>
                          setNewItem({ ...newItem, productName: e.target.value })
                        }
                        required
                      />
                    </div>
                    <div className="form-group">
                      <label>Price</label>
                      <input
                        type="text"
                        placeholder="e.g., Rs 65 / Inch"
                        value={newItem.productPrice || ""}
                        onChange={(e) =>
                          setNewItem({ ...newItem, productPrice: e.target.value })
                        }
                        required
                      />
                    </div>
                    <div className="form-group">
                      <label>Description</label>
                      <textarea
                        placeholder="Product description"
                        value={newItem.productDescription || ""}
                        onChange={(e) =>
                          setNewItem({
                            ...newItem,
                            productDescription: e.target.value,
                          })
                        }
                        rows="3"
                      />
                    </div>
                    <div className="form-group">
                      <label>Product Images (optional)</label>
                      <input
                        type="file"
                        accept="image/*"
                        multiple
                        onChange={(e) =>
                          setNewItem({ ...newItem, productFiles: Array.from(e.target.files) })
                        }
                      />
                    </div>
                    <div className="form-group">
                      <label>Specifications (optional)</label>
                      {(newItem.specs || []).map((s, si) => (
                        <div key={si} className="flex items-center gap-2 mb-2">
                          <input className="w-1/3" placeholder="Key (e.g., Color)" value={s.key} onChange={(e)=>{
                            const specs = [...(newItem.specs||[])]; specs[si].key = e.target.value; setNewItem({...newItem, specs});
                          }} />
                          <input className="flex-1" placeholder="Value (e.g., Red)" value={s.value} onChange={(e)=>{
                            const specs = [...(newItem.specs||[])]; specs[si].value = e.target.value; setNewItem({...newItem, specs});
                          }} />
                          <button type="button" className="text-sm text-red-600" onClick={()=>{
                            const specs = [...(newItem.specs||[])]; specs.splice(si,1); setNewItem({...newItem, specs});
                          }}>Remove</button>
                        </div>
                      ))}
                      <button type="button" className="text-sm font-medium text-indigo-600" onClick={()=>{
                        const specs = [...(newItem.specs||[])]; specs.push({key:'', value:''}); setNewItem({...newItem, specs});
                      }}>+ Add Specification</button>
                    </div>
                  </>
                )}

                <div className="flex gap-2 mt-4">
                  <button type="submit" className="inline-flex items-center gap-2 px-3 py-2 text-white bg-green-600 rounded hover:bg-green-700">
                    <Save size={18} /> Add
                  </button>
                  <button
                    type="button"
                    className="inline-flex items-center gap-2 px-3 py-2 text-white bg-red-600 rounded hover:bg-red-700"
                    onClick={() => {
                      setShowAddForm(false);
                      setNewItem({});
                      setNewItemType("");
                    }}
                  >
                    <X size={18} /> Cancel
                  </button>
                </div>
              </form>
            )}

            <div className="space-y-8 categories-list">
              {data.categories.map((category) => (
                <div key={category.category} className="pl-4 border-l-4 border-indigo-600">
                  {editingId === category.category ? (
                    <form className="mb-4 edit-form">
                      <div className="form-group">
                        <label>Category Name</label>
                        <input
                          type="text"
                          value={editData.category || ""}
                          onChange={(e) =>
                            setEditData({ ...editData, category: e.target.value })
                          }
                        />
                      </div>
                      <div className="flex gap-2 mt-3">
                        <button
                          type="button"
                          className="inline-flex items-center gap-2 px-3 py-2 text-white bg-green-600 rounded hover:bg-green-700"
                          onClick={() =>
                            handleEditSave("category", category.category)
                          }
                        >
                          <Save size={18} /> Save
                        </button>
                        <button
                          type="button"
                          className="inline-flex items-center gap-2 px-3 py-2 text-white bg-red-600 rounded hover:bg-red-700"
                          onClick={() => setEditingId(null)}
                        >
                          <X size={18} /> Cancel
                        </button>
                      </div>
                    </form>
                  ) : (
                    <div className="flex items-center gap-3 mb-4">
                      <h3 className="text-lg font-bold">{category.category}</h3>
                      <button
                        className="inline-flex items-center p-1.5 text-sm text-white rounded bg-amber-500 hover:bg-amber-600"
                        onClick={() => {
                          setEditingId(category.category);
                          setEditData(category);
                        }}
                      >
                        <Edit2 size={16} />
                      </button>
                      <button
                        className="inline-flex items-center p-1.5 text-sm text-white bg-red-600 rounded hover:bg-red-700"
                        onClick={() =>
                          handleDelete("category", category.category)
                        }
                      >
                        <Trash2 size={16} />
                      </button>
                      <button
                        className="inline-flex items-center gap-2 px-3 py-1.5 text-sm text-white bg-indigo-600 rounded hover:bg-indigo-700 ml-auto"
                        onClick={() => {
                          setShowAddForm(true);
                          setNewItemType('product');
                          setNewItem({ categorySelect: category.category });
                        }}
                      >
                        <Plus size={16} /> Add Product
                      </button>
                    </div>
                  )}

                  {/* Products grid - 3 columns */}
                  <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3">
                    {category.subProducts?.map((product) => (
                      <div key={product.name} className="overflow-hidden transition bg-white border rounded-lg shadow-sm border-slate-200 hover:shadow-md">
                        {editingId === product.name ? (
                          <form className="p-4 edit-form">
                            <div className="form-group">
                              <label>Name</label>
                              <input
                                type="text"
                                value={editData.name || ""}
                                onChange={(e) =>
                                  setEditData({
                                    ...editData,
                                    name: e.target.value,
                                  })
                                }
                              />
                            </div>
                            <div className="form-group">
                              <label>Price</label>
                              <input
                                type="text"
                                value={editData.price || ""}
                                onChange={(e) =>
                                  setEditData({
                                    ...editData,
                                    price: e.target.value,
                                  })
                                }
                              />
                            </div>
                            <div className="form-group">
                              <label>Description</label>
                              <textarea
                                value={editData.description || ""}
                                onChange={(e) =>
                                  setEditData({
                                    ...editData,
                                    description: e.target.value,
                                  })
                                }
                                rows="2"
                              />
                            </div>
                            <div className="mt-3 form-group">
                              <label>Upload Images</label>
                              <input
                                type="file"
                                accept="image/*"
                                multiple
                                onChange={(e) =>
                                  setEditData({ ...editData, newFiles: Array.from(e.target.files) })
                                }
                              />
                            </div>

                            {/* Specs editor */}
                            <div className="mt-3 form-group">
                              <label>Specifications</label>
                              {(editData.specs || []).map((s, si) => (
                                <div key={si} className="flex items-center gap-2 mb-2">
                                  <input className="w-1/3" placeholder="Key" value={s.key} onChange={(e)=>{
                                    const specs = [...(editData.specs||[])]; specs[si].key = e.target.value; setEditData({...editData, specs});
                                  }} />
                                  <input className="flex-1" placeholder="Value" value={s.value} onChange={(e)=>{
                                    const specs = [...(editData.specs||[])]; specs[si].value = e.target.value; setEditData({...editData, specs});
                                  }} />
                                  <button type="button" className="text-sm text-red-600" onClick={()=>{
                                    const specs = [...(editData.specs||[])]; specs.splice(si,1); setEditData({...editData, specs});
                                  }}>Remove</button>
                                </div>
                              ))}
                              <div>
                                <button type="button" className="text-sm text-indigo-600" onClick={()=>{
                                  const specs = [...(editData.specs||[])]; specs.push({key:'', value:''}); setEditData({...editData, specs});
                                }}>+ Add spec</button>
                              </div>
                            </div>

                            {/* Existing images with remove toggle */}
                            <div className="mt-3 existing-images">
                              <label>Existing Images</label>
                              <div className="flex flex-wrap gap-2 mt-2">
                                {(editData.images || []).map((img, ii) => {
                                  const removed = (editData.removedImages || []).includes(img);
                                  return (
                                    <div key={ii} className="relative">
                                      <img src={getFullUrl(img)} className={`w-24 h-24 object-cover rounded ${removed? 'opacity-40':''}`} onError={(e)=>e.target.src='/images/placeholder.jpg'} />
                                      <button type="button" className={`absolute top-1 right-1 bg-white rounded-full p-1 ${removed? 'text-green-600':'text-red-600'}`} onClick={()=>{
                                        const cur = new Set(editData.removedImages || []);
                                        if (cur.has(img)) cur.delete(img); else cur.add(img);
                                        setEditData({...editData, removedImages: Array.from(cur)});
                                      }}>{removed? 'Undo':'Remove'}</button>
                                    </div>
                                  )
                                })}
                              </div>
                            </div>

                            <div className="flex gap-2 mt-4">
                              <button
                                type="button"
                                className="inline-flex items-center gap-2 px-3 py-2 text-white bg-green-600 rounded hover:bg-green-700"
                                onClick={() =>
                                  handleEditSave("product", product.name)
                                }
                              >
                                <Save size={18} /> Save
                              </button>
                              <button
                                type="button"
                                className="inline-flex items-center gap-2 px-3 py-2 text-white bg-red-600 rounded hover:bg-red-700"
                                onClick={() => setEditingId(null)}
                              >
                                <X size={18} /> Cancel
                              </button>
                            </div>
                          </form>
                        ) : (
                          <>
                            <img src={getFullUrl(product.images?.[0])} alt={product.name} className="object-cover w-full h-40" onError={(e)=>e.target.src='/images/placeholder.jpg'} />
                            <div className="p-4">
                              <h4 className="font-semibold truncate text-slate-800">{product.name}</h4>
                              <p className="mt-1 text-sm font-bold text-indigo-600">{product.price}</p>
                              <p className="mt-2 text-xs text-slate-600 line-clamp-2">{product.description}</p>
                              {(product.specs || []).length > 0 && (
                                <div className="mt-2">
                                  <p className="mb-1 text-xs font-medium text-slate-700">Specs:</p>
                                  <div className="text-xs text-slate-600 space-y-0.5">
                                    {product.specs.slice(0, 2).map((s, si) => (
                                      <div key={si}><span className="font-medium">{s.key}:</span> {s.value}</div>
                                    ))}
                                    {product.specs.length > 2 && <div className="text-slate-500">+{product.specs.length - 2} more</div>}
                                  </div>
                                </div>
                              )}
                              <div className="flex gap-2 mt-3">
                                <button
                                  className="flex-1 inline-flex items-center justify-center p-1.5 text-xs text-white rounded bg-amber-500 hover:bg-amber-600"
                                  onClick={() => {
                                    setEditingId(product.name);
                                    setEditData({ ...product, removedImages: [] });
                                  }}
                                >
                                  <Edit2 size={14} />
                                </button>
                                <button
                                  className="flex-1 inline-flex items-center justify-center p-1.5 text-xs text-white bg-red-600 rounded hover:bg-red-700"
                                  onClick={() =>
                                    handleDelete("product", product.name)
                                  }
                                >
                                  <Trash2 size={14} />
                                </button>
                              </div>
                            </div>
                          </>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Gallery Tab */}
        {activeTab === "gallery" && data?.gallery && (
          <div className="section">
            <h2>Gallery</h2>
            <button
              className="inline-flex items-center gap-2 px-3 py-2 text-white bg-indigo-600 rounded hover:bg-indigo-700"
              onClick={() => {
                setShowAddForm(true);
                setNewItemType("gallery");
              }}
            >
              <Plus size={18} /> Add Gallery Item
            </button>

                {showAddForm && newItemType === "gallery" && (
              <form className="add-form" onSubmit={handleAddNew}>
                <div className="form-group">
                  <label>Title</label>
                  <input
                    type="text"
                    placeholder="Gallery item title"
                    value={newItem.galleryTitle || ""}
                    onChange={(e) =>
                      setNewItem({ ...newItem, galleryTitle: e.target.value })
                    }
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Image URL (optional if uploading files)</label>
                  <input
                    type="text"
                    placeholder="e.g., /images/gallery1.jpg"
                    value={newItem.galleryImage || ""}
                    onChange={(e) =>
                      setNewItem({ ...newItem, galleryImage: e.target.value })
                    }
                  />
                </div>
                <div className="form-group">
                  <label>Upload Images</label>
                  <input
                    type="file"
                    accept="image/*"
                    multiple
                    onChange={(e) => setNewItem({ ...newItem, galleryFiles: Array.from(e.target.files) })}
                  />
                </div>
                <div className="flex gap-2 mt-4">
                  <button type="submit" className="inline-flex items-center gap-2 px-3 py-2 text-white bg-green-600 rounded hover:bg-green-700">
                    <Save size={18} /> Add
                  </button>
                  <button
                    type="button"
                    className="inline-flex items-center gap-2 px-3 py-2 text-white bg-red-600 rounded hover:bg-red-700"
                    onClick={() => {
                      setShowAddForm(false);
                      setNewItem({});
                      setNewItemType("");
                    }}
                  >
                    <X size={18} /> Cancel
                  </button>
                </div>
              </form>
            )}

            <div className="grid grid-cols-1 gap-4 gallery-list md:grid-cols-2 lg:grid-cols-3">
              {data.gallery.map((item) => (
                <div key={item.id} className="overflow-hidden transition bg-white border rounded-lg shadow-sm border-slate-200 hover:shadow-md">
                  {editingId === item.id ? (
                    <form className="p-4 edit-form">
                      <div className="form-group">
                        <label>Title</label>
                        <input
                          type="text"
                          value={editData.title || ""}
                          onChange={(e) =>
                            setEditData({ ...editData, title: e.target.value })
                          }
                        />
                      </div>
                      <div className="form-group">
                        <label>Image URL</label>
                        <input
                          type="text"
                          value={editData.image || ""}
                          onChange={(e) =>
                            setEditData({ ...editData, image: e.target.value })
                          }
                        />
                      </div>
                      <div className="form-group">
                        <label>Replace / Upload Image</label>
                        <input
                          type="file"
                          accept="image/*"
                          onChange={(e) => setEditData({ ...editData, newFiles: Array.from(e.target.files) })}
                        />
                      </div>
                      <div className="flex gap-2 mt-3">
                        <button
                          type="button"
                          className="inline-flex items-center gap-2 px-3 py-2 text-white bg-green-600 rounded hover:bg-green-700"
                          onClick={() => handleEditSave("gallery", item.id)}
                        >
                          <Save size={18} /> Save
                        </button>
                        <button
                          type="button"
                          className="inline-flex items-center gap-2 px-3 py-2 text-white bg-red-600 rounded hover:bg-red-700"
                          onClick={() => setEditingId(null)}
                        >
                          <X size={18} /> Cancel
                        </button>
                      </div>
                    </form>
                  ) : (
                    <>
                      <img
                        src={getFullUrl(item.image)}
                        alt={item.title}
                        className="object-cover w-full h-48"
                        onError={(e) => (e.target.src = '/images/placeholder.jpg')}
                      />
                      <div className="p-3">
                        <p className="font-semibold truncate text-slate-800">{item.title}</p>
                        <div className="flex gap-2 mt-3">
                          <button
                            className="flex-1 inline-flex items-center justify-center p-1.5 text-xs text-white rounded bg-amber-500 hover:bg-amber-600"
                            onClick={() => {
                              setEditingId(item.id);
                              setEditData(item);
                            }}
                          >
                            <Edit2 size={14} />
                          </button>
                          <button
                            className="flex-1 inline-flex items-center justify-center p-1.5 text-xs text-white bg-red-600 rounded hover:bg-red-700"
                            onClick={() => handleDelete("gallery", item.id)}
                          >
                            <Trash2 size={14} />
                          </button>
                        </div>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Clients Tab */}
        {activeTab === "clients" && data?.clients && (
          <div className="section">
            <h2>Our Clients</h2>
            <button
              className="inline-flex items-center gap-2 px-3 py-2 text-white bg-indigo-600 rounded hover:bg-indigo-700"
              onClick={() => {
                setShowAddForm(true);
                setNewItemType("client");
              }}
            >
              <Plus size={18} /> Add Client
            </button>

            {showAddForm && newItemType === "client" && (
              <form className="add-form" onSubmit={handleAddNew}>
                <div className="form-group">
                  <label>Client Name</label>
                  <input
                    type="text"
                    placeholder="Client name"
                    value={newItem.clientName || ""}
                    onChange={(e) =>
                      setNewItem({ ...newItem, clientName: e.target.value })
                    }
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Logo/Image URL (optional)</label>
                  <input
                    type="text"
                    placeholder="e.g., /images/client1.jpg"
                    value={newItem.clientImage || ""}
                    onChange={(e) =>
                      setNewItem({ ...newItem, clientImage: e.target.value })
                    }
                  />
                </div>
                <div className="form-group">
                  <label>Upload Logo (optional)</label>
                  <input
                    type="file"
                    accept="image/*"
                    onChange={(e) => setNewItem({ ...newItem, clientFiles: Array.from(e.target.files) })}
                  />
                </div>
                <div className="flex gap-2 mt-4">
                  <button type="submit" className="inline-flex items-center gap-2 px-3 py-2 text-white bg-green-600 rounded hover:bg-green-700">
                    <Save size={18} /> Add
                  </button>
                  <button
                    type="button"
                    className="inline-flex items-center gap-2 px-3 py-2 text-white bg-red-600 rounded hover:bg-red-700"
                    onClick={() => {
                      setShowAddForm(false);
                      setNewItem({});
                      setNewItemType("");
                    }}
                  >
                    <X size={18} /> Cancel
                  </button>
                </div>
              </form>
            )}

            <div className="grid grid-cols-1 gap-4 clients-list md:grid-cols-2 lg:grid-cols-3">
              {data.clients.map((client, idx) => (
                <div key={idx} className="overflow-hidden transition bg-white border rounded-lg shadow-sm border-slate-200 hover:shadow-md">
                  {editingId === `client-${idx}` ? (
                    <form className="p-4 edit-form">
                      <div className="form-group">
                        <label>Name</label>
                        <input
                          type="text"
                          value={editData.name || client}
                          onChange={(e) =>
                            setEditData({ ...editData, name: e.target.value })
                          }
                        />
                      </div>
                      <div className="flex gap-2 mt-3">
                        <button
                          type="button"
                          className="inline-flex items-center gap-2 px-3 py-2 text-white bg-green-600 rounded hover:bg-green-700"
                          onClick={() => handleEditSave("client", idx)}
                        >
                          <Save size={18} /> Save
                        </button>
                        <button
                          type="button"
                          className="inline-flex items-center gap-2 px-3 py-2 text-white bg-red-600 rounded hover:bg-red-700"
                          onClick={() => setEditingId(null)}
                        >
                          <X size={18} /> Cancel
                        </button>
                      </div>
                    </form>
                  ) : (
                    <>
                      <div className="flex items-center justify-center h-32 p-3 bg-gradient-to-br from-indigo-100 to-indigo-50">
                        <p className="font-semibold text-center text-indigo-700 truncate">{client}</p>
                      </div>
                      <div className="flex gap-2 p-3">
                        <button
                          className="flex-1 inline-flex items-center justify-center p-1.5 text-xs text-white rounded bg-amber-500 hover:bg-amber-600"
                          onClick={() => {
                            setEditingId(`client-${idx}`);
                            setEditData({ name: client });
                          }}
                        >
                          <Edit2 size={14} />
                        </button>
                        <button
                          className="flex-1 inline-flex items-center justify-center p-1.5 text-xs text-white bg-red-600 rounded hover:bg-red-700"
                          onClick={() => handleDelete("client", idx)}
                        >
                          <Trash2 size={14} />
                        </button>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
        </main>
      </div>
    </div>
  );
};

export default AdminDashboard;
